using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems() =>
    [
        new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
        new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
    ];

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45.50m, order.Total); // (10*2) + (25.50*1)
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsCorrectTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Single", Price = 7.99m, Quantity = 3 },
        };

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(23.97m, order.Total);
        Assert.ContainsSingle(order.Items);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToApproximatelyNow()
    {
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", CreateSampleItems());

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateSampleItems()));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateSampleItems());

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        _service.CreateOrder("cust-A", CreateSampleItems());
        _service.CreateOrder("cust-A", CreateSampleItems());
        _service.CreateOrder("cust-B", CreateSampleItems());

        var orders = _service.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("nobody");

        Assert.IsEmpty(orders);
    }

    #endregion

    #region DynamicData — total calculation

    [TestMethod]
    [DynamicData(nameof(TotalTestData))]
    public void CreateOrder_CalculatesExpectedTotal(decimal price, int qty, decimal expected)
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = price, Quantity = qty },
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expected, order.Total);
    }

    public static IEnumerable<(decimal price, int qty, decimal expected)> TotalTestData =>
    [
        (10.00m, 1, 10.00m),
        (5.50m, 4, 22.00m),
        (0.01m, 100, 1.00m),
        (99.99m, 0, 0.00m),
    ];

    #endregion
}

